class Solution {
    public boolean checkPalindromeFormation(String a, String b) {
        int len = Math.min(a.length(), b.length());
        String[] aSplit = new String[len];
        String[] bSplit = new String[len];
        for (int i = 0; i < len; i++) {
            aSplit[i] = a.substring(0, i + 1);
            bSplit[i] = b.substring(0, i + 1);
        }
        String aPrefix = aSplit[0];
        String aSuffix = aSplit[len - 1];
        String bPrefix = bSplit[0];
        String bSuffix = bSplit[len - 1];
        return aPrefix.equals(bSuffix) || aSuffix.equals(bPrefix;
    }
}
